int potPin = 14;
int segPins[7] = {2, 3, 4, 5, 6, 7, 8};

void setup() {
  for (int i = 0; i < 7; i++) {
    pinMode(segPins[i], OUTPUT);
  }
}

void loop() {
  int rawValue = analogRead(potPin);
  int digit = map(rawValue, 0, 1023, 0, 9);
  displayDigit(digit);
}

void displayDigit(int digit) {
  int a, b, c, d, e, f, g;

  if (digit == 0) {
    a = 1; b = 1; c = 1; d = 1; e = 1; f = 1; g = 0;
  } else if (digit == 1) {
    a = 0; b = 1; c = 1; d = 0; e = 0; f = 0; g = 0;
  } else if (digit == 2) {
    a = 1; b = 1; c = 0; d = 1; e = 1; f = 0; g = 1;
  } else if (digit == 3) {
    a = 1; b = 1; c = 1; d = 1; e = 0; f = 0; g = 1;
  } else if (digit == 4) {
    a = 0; b = 1; c = 1; d = 0; e = 0; f = 1; g = 1;
  } else if (digit == 5) {
    a = 1; b = 0; c = 1; d = 1; e = 0; f = 1; g = 1;
  } else if (digit == 6) {
    a = 1; b = 0; c = 1; d = 1; e = 1; f = 1; g = 1;
  } else if (digit == 7) {
    a = 1; b = 1; c = 1; d = 0; e = 0; f = 0; g = 0;
  } else if (digit == 8) {
    a = 1; b = 1; c = 1; d = 1; e = 1; f = 1; g = 1;
  } else if (digit == 9) {
    a = 1; b = 1; c = 1; d = 1; e = 0; f = 1; g = 1;
  }

  digitalWrite(segPins[0], a);
  digitalWrite(segPins[1], b);
  digitalWrite(segPins[2], c);
  digitalWrite(segPins[3], d);
  digitalWrite(segPins[4], e);
  digitalWrite(segPins[5], f);
  digitalWrite(segPins[6], g);
}

