int potPin = 14;
int segPins[7] = {2, 3, 4, 5, 6, 7, 8};

void setup() {
  Serial.begin(9600);
  for (int i = 0; i < 7; i++) {
    pinMode(segPins[i], OUTPUT);
  }
}

void loop() {
  int rawValue = analogRead(potPin);
  int digit = map(rawValue, 0, 1023, 0, 9);

  // Map raw value (0-1023) to angle (0-270 degrees, typical pot range)
  float angle = map(rawValue, 0, 1023, 0, 270);

  // Display angle in Serial Monitor
  Serial.print("Raw: ");
  Serial.print(rawValue);
  Serial.print(" | Angle: ");
  Serial.print(angle);
  Serial.print("° | Digit: ");
  Serial.println(digit);

  displayDigit(digit);
  delay(100);
}

